import React, { useEffect, useRef } from 'react';

const VideoFrame = ({ src, onError }) => {
  const containerRef = useRef(null);

  useEffect(() => {
    if (src && containerRef.current) {
      // Crear iframe sin sandbox para evitar "Client blocked"
      const frame = document.createElement('iframe');

      // Solo atributos esenciales
      frame.src = src;
      frame.width = '100%';
      frame.height = '100%';
      frame.allowFullscreen = true;

      // Sin sandbox - solo bloqueo de clics
      frame.style.cssText = `
        border: none;
        background: #000;
        border-radius: 8px;
        width: 100%;
        height: 100%;
        pointer-events: none;
      `;

      // Limpiar y agregar
      containerRef.current.innerHTML = '';
      containerRef.current.appendChild(frame);

      frame.onload = () => {
        console.log('Iframe cargado sin sandbox');
      };

      // Verificar si carga
      const checkLoad = setTimeout(() => {
        try {
          if (!frame.contentWindow) {
            console.log('Iframe no cargó correctamente');
            if (onError) onError();
          }
        } catch (e) {
          console.log('Error verificando iframe:', e.message);
          if (onError) onError();
        }
      }, 5000);

      return () => {
        clearTimeout(checkLoad);
        if (containerRef.current) {
          containerRef.current.innerHTML = '';
        }
      };
    }
  }, [src, onError]);

  return (
    <div 
      ref={containerRef}
      className="w-full h-96 md:h-[500px] lg:h-[600px] bg-black rounded-lg relative overflow-hidden"
      style={{ 
        minHeight: '400px'
      }}
    >
      {/* Máscaras sutiles para ocultar anuncios overlay */}
      <div className="absolute inset-0 pointer-events-none z-15">
        {/* Ocultar anuncios en esquinas superiores */}
        <div className="absolute top-0 right-0 w-40 h-32 bg-gradient-to-bl from-black via-black to-transparent opacity-90"></div>
        <div className="absolute top-0 left-0 w-40 h-24 bg-gradient-to-br from-black via-black to-transparent opacity-90"></div>

        {/* Ocultar banners centrales */}
        <div className="absolute top-1/4 left-1/2 transform -translate-x-1/2 w-96 h-20 bg-gradient-to-r from-transparent via-black to-transparent opacity-95"></div>

        {/* Ocultar botones X y anuncios flotantes */}
        <div className="absolute top-2 right-2 w-8 h-8 bg-black rounded-full opacity-100"></div>
        <div className="absolute top-2 right-12 w-20 h-6 bg-black rounded opacity-90"></div>

        {/* Ocultar anuncios en el centro */}
        <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-80 h-60">
          <div className="w-full h-full bg-gradient-radial from-transparent via-transparent to-black opacity-70 rounded-lg"></div>
        </div>
      </div>

      {/* Capa de protección anti-anuncios */}
      <div 
        className="absolute inset-0 z-10 bg-transparent"
        onClick={(e) => {
          e.preventDefault();
          e.stopPropagation();
          // No mostrar mensaje para ser más sutil
        }}
      >
        {/* Área del reproductor - más grande y centrada */}
        <div 
          className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-32 h-32 bg-transparent rounded-full flex items-center justify-center"
          style={{ pointerEvents: 'none' }}
        >
          {/* Botón de play sutil */}
          <div 
            className="w-16 h-16 bg-black bg-opacity-50 rounded-full flex items-center justify-center cursor-pointer hover:bg-opacity-70 transition-all"
            style={{ pointerEvents: 'auto' }}
            onClick={(e) => {
              e.stopPropagation();
              const iframe = containerRef.current?.querySelector('iframe');
              if (iframe) {
                iframe.style.pointerEvents = 'auto';
                setTimeout(() => {
                  iframe.style.pointerEvents = 'none';
                }, 2000);
              }
            }}
          >
            <span className="text-white text-xl ml-1">▶️</span>
          </div>
        </div>
      </div>

      {/* Botón de control discreto */}
      <button
        className="absolute bottom-2 right-2 z-30 bg-gray-800 bg-opacity-70 hover:bg-opacity-90 text-white px-2 py-1 rounded text-xs"
        onClick={() => {
          const iframe = containerRef.current?.querySelector('iframe');
          if (iframe) {
            iframe.style.pointerEvents = 'auto';
            setTimeout(() => {
              iframe.style.pointerEvents = 'none';
            }, 3000);
          }
        }}
      >
        ⚙️
      </button>
    </div>
  );
};

export default VideoFrame;
